import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Zap, Eye, EyeOff, AlertCircle } from 'lucide-react';

const DEMO_ACCOUNTS = [
  { label: 'Admin',        email: 'admin@neurofleetx.com',    role: 'ADMIN',        color: '#fbbf24' },
  { label: 'Fleet Mgr',   email: 'manager@neurofleetx.com',  role: 'FLEET_MANAGER', color: '#60a5fa' },
  { label: 'Driver',      email: 'driver@neurofleetx.com',   role: 'DRIVER',        color: '#34d399' },
  { label: 'Customer',    email: 'customer@neurofleetx.com', role: 'CUSTOMER',      color: '#a78bfa' },
];

export default function LoginPage() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [showPass, setShowPass] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await login(form.email, form.password);
      navigate('/');
    } catch {
      setError('Invalid email or password');
    } finally { setLoading(false); }
  };

  const fillDemo = (email) => setForm({ email, password: 'password123' });

  return (
    <div className="min-h-screen flex items-center justify-center p-4 grid-bg"
      style={{ background: 'var(--bg-dark)' }}>
      <div className="w-full max-w-md">
        {/* Logo */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl mb-4"
            style={{ background: 'linear-gradient(135deg,#00d4ff,#0284c7)', boxShadow: '0 0 40px rgba(0,212,255,0.4)' }}>
            <Zap size={28} className="text-white" />
          </div>
          <h1 className="text-3xl font-bold text-white">NeuroFleetX</h1>
          <p className="text-slate-400 mt-1 text-sm">AI-Driven Urban Mobility Platform</p>
        </div>

        {/* Card */}
        <div className="nfx-card p-8 animated-border">
          <h2 className="text-xl font-bold text-white mb-6">Sign In</h2>

          {error && (
            <div className="flex items-center gap-2 mb-4 p-3 rounded-lg text-sm"
              style={{ background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.3)', color: '#f87171' }}>
              <AlertCircle size={16} />{error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Email</label>
              <input
                type="email" required
                value={form.email}
                onChange={e => setForm(f => ({ ...f, email: e.target.value }))}
                className="w-full px-4 py-2.5 rounded-lg text-sm text-white outline-none transition-all"
                style={{ background: '#0d1117', border: '1px solid rgba(0,212,255,0.2)', color: 'white' }}
                placeholder="you@example.com"
                onFocus={e => e.target.style.borderColor = '#00d4ff'}
                onBlur={e => e.target.style.borderColor = 'rgba(0,212,255,0.2)'}
              />
            </div>
            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Password</label>
              <div className="relative">
                <input
                  type={showPass ? 'text' : 'password'} required
                  value={form.password}
                  onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
                  className="w-full px-4 py-2.5 rounded-lg text-sm outline-none pr-10"
                  style={{ background: '#0d1117', border: '1px solid rgba(0,212,255,0.2)', color: 'white' }}
                  placeholder="••••••••"
                  onFocus={e => e.target.style.borderColor = '#00d4ff'}
                  onBlur={e => e.target.style.borderColor = 'rgba(0,212,255,0.2)'}
                />
                <button type="button" onClick={() => setShowPass(v => !v)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white">
                  {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            <button type="submit" disabled={loading}
              className="w-full py-3 rounded-lg font-semibold text-sm text-white transition-all mt-2"
              style={{ background: loading ? '#1e3a5f' : 'linear-gradient(135deg,#00d4ff,#0284c7)',
                       boxShadow: loading ? 'none' : '0 4px 20px rgba(0,212,255,0.3)' }}>
              {loading ? 'Signing in...' : 'Sign In'}
            </button>
          </form>

          <p className="text-center text-slate-400 text-sm mt-4">
            No account?{' '}
            <Link to="/register" className="hover:text-white transition-colors" style={{ color: '#00d4ff' }}>
              Register
            </Link>
          </p>
        </div>

        {/* Demo accounts */}
        <div className="mt-6 nfx-card p-4">
          <p className="text-xs text-slate-500 mb-3 text-center">DEMO ACCOUNTS — password: <span className="font-mono" style={{ color: '#00d4ff' }}>password123</span></p>
          <div className="grid grid-cols-2 gap-2">
            {DEMO_ACCOUNTS.map(a => (
              <button key={a.email} onClick={() => fillDemo(a.email)}
                className="px-3 py-2 rounded-lg text-xs text-left transition-all hover:scale-105"
                style={{ background: `${a.color}15`, border: `1px solid ${a.color}40`, color: a.color }}>
                <div className="font-semibold">{a.label}</div>
                <div className="text-xs opacity-60 font-mono truncate">{a.email.split('@')[0]}</div>
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
